\label{Thm Blowup O} Let $\mathbb{H}^N$ be the Heisenberg group with homogeneous dimension $Q:=2N+2,$ and 
	let $\gamma\in [0,1)$ and $\alpha\in (-1,0).$ We assume that  
	\begin{align}
		 \int_{\mathbbm{H}^N}\|\xi\|_H^{-\mu(\lambda)}u_0(\xi)d\xi<\infty,\,0< \int_{\mathbbm{H}^N}\|\xi\|_H^{-\mu(\lambda)}f(\xi)d\xi<\infty.
	\end{align} 
	Then, for any $1<p<\frac{Q+2\gamma-\mu(\lambda)-2\alpha}{Q-2-\mu(\lambda)-2\alpha}$,  problem \eqref{eq 0.1} does not admit a global-in-time weak solution.

\label{Thm Blowup O2} Let $\mathbb{H}^N$ be the Heisenberg group with homogeneous dimension $Q:=2N+2,$ and
	let $\gamma\in [0,1)$ and  $\alpha\in (0,\infty).$ We assume that 	\begin{align}
		\int_{\mathbbm{H}^N}\|\xi\|_H^{-\mu(\lambda)}u_0(\xi)d\xi<\infty,\,0< \int_{\mathbbm{H}^N}\|\xi\|_H^{-\mu(\lambda)}f(\xi)d\xi<\infty.
	\end{align}   
	Then, for any $p>1,$ problem \eqref{eq 0.1} does not admit a global-in-time weak solution.

