\cite{Gre}
	The heat semigroup associated with $-\Delta_{H}$ satisfies the following estimate:
	\begin{align}\label{infty}
		\|e^{t\Delta_{H}}g\|_{L^\infty(\mathbbm{H}^N)}\leq \|g\|_{L^\infty(\mathbbm{H}^N)},
	\end{align}
	for any $g\in L^\infty(\mathbbm{H}^N)$ and $t>0.$

[Beta function]
	The Beta function $B(z_1,z_2)$ is a function of two complex variables $z_1,\,z_2,$ defined as
	\begin{align}\label{Beta}
		B(z_1,z_2)=\int_0^1t^{z_1-1}(1-t)^{z_2-1}dt,\,\, \mathcal{R}e(z_i)>0,\,i=1,2.
	\end{align}
	This integral is also known as the Eulerian integral of the first kind.

[Riemann-Liouville fractional integral \cite{Kilbas}] For a given integrable function $u(t),$ $t\in (0,T),$ the left and right Riemann–Liouville fractional integrals of order $\gamma\in (0,1)$ are defined as 
	\begin{align}
		I_{0+}^\gamma u(t)=\frac{1}{\Gamma(\gamma)}\int_0^t(t-\tau)^{\gamma-1}u(\tau)d\tau,
	\end{align}
	and
	\begin{align}
		I_{T-}^\gamma u(t)=\frac{1}{\Gamma(\gamma)}\int_t^T(\tau-t)^{\gamma-1}u(\tau)d\tau,
	\end{align}
	respectively. Moreover, $I_{T-}^\gamma u, I_{0+}^\gamma u\longrightarrow u$ a.e. as $\gamma\longrightarrow 0,$ see \cite{Kilbas}. In view of it, we use the convention that $I_{T-}^0 u(t), I_{0+}^0 u(t)=u(t), t\in (0,T).$

