[Lemma 2.2 \cite{Dou}]\label{Hardy} Let $f\in C_c^\infty(\mathbbm{H}^N)\setminus\{0\}.$ Then
	\begin{align}
		\int_{\mathbbm{H}^N}\frac{(f(\xi))^2}{\|\xi\|_H^{2}}\psi(\xi)d\xi\leq \left(\frac{2}{Q-2}\right)^2\int_{\mathbbm{H}^N}|\nabla_{H}f(\xi)|^2d\xi,
	\end{align}
	where $\psi=|\nabla_{H}\|\cdot\|_{H}|^2.$ Moreover, the constant $\left(\frac{2}{Q-2}\right)^2$ appearing in the inequality is sharp.

[Folland-Stein-Sobolev inequality \cite{FollSte}]\label{Thm Folst}
	Let $1<p<\infty.$ Then, there exists a constant $C=C(p,Q)$ such that 
	\begin{align}
		\left(\int_{\mathbbm{H}^N}|\phi|^{\frac{pQ}{Q-p}}d\xi\right)^{\frac{Q-p}{pQ}} \leq C(p,Q)\left(\int_{\mathbbm{H}^N}|\nabla_H\phi|^p\right)^{\frac{1}{p}}
	\end{align}	
	for all $\phi\in C_c^\infty(\mathbbm{H}^N).$

\label{Thm Blowup O4}
	Let $\gamma=0,$  $\alpha\in (-1,\infty),$ and let  $0\leq u_0,f\in L^\infty(\mathbbm{H}^N).$ Then, for any $p>
	\frac{\mu(\lambda)+2}{\mu(\lambda)},$ problem \eqref{eq 0.1} does not admit a local-in-time solution.

\label{Thm Blowup O5}
	Let $\gamma>0,$ $\alpha\in (-1,\infty),$ and let  $0\leq u_0,f\in L^\infty(\mathbbm{H}^N).$ Assume that \ref{H1} holds. Then, for any $p>
	\frac{\mu(\lambda)+2}{\mu(\lambda)},$ problem \eqref{eq 0.1} does not admit a local-in-time weak solution.

[Mild solution]\label{Mild}
	A function $u\in C([0,T],L^\infty(\mathbbm{H}^N))$ is called a local-in-time mild solution to \eqref{eq without} if
	\begin{align}\label{eq Mild}
		u(t)=e^{t\Delta_{H}}u_0+\int_0^te^{(t-\tau)\Delta_{H}}\left(\frac{1}{\Gamma (\gamma)}\int_0^\tau(\tau-s)^{-\gamma}|u(s)|^{p}ds+\tau^\alpha f\right)d\tau
	\end{align}
	holds for any $t\in (0,T].$

[Weak solution]\label{Weak2}
	Let $u_0,f\in L^1_{\text{loc}}(\mathbbm{H}^N).$ Then $u\in L^p_{\text{loc}}((0,T),L^p_{\text{loc}}(\mathbbm{H}^N))$ is called a local-in-time weak solution to \eqref{eq without} if 
	\begin{align}
		-\int_0^T\int_{\mathbbm{H}^N}u(\partial_t\phi+\Delta_{H}\phi)d\xi dt =\int_0^T\int_{\mathbbm{H}^N}|u|^pI_{T^-}^\gamma\phi d\xi dt +\int_{\mathbbm{H}^N}u_0\phi(0,\cdot)d\xi +\int_0^T\int_{\mathbbm{H}^N} \tau^\alpha f\phi d\xi d\tau,
	\end{align}
	holds for any non-negative test function $\phi\in C_c^1([0,T),C_c^2(\mathbbm{H}^N)).$ 
	Moreover, $u$ is called a global-in-time weak solution if $T=+\infty.$

\label{Local}
	Let $\gamma>0,$ $\alpha\in(-1,\infty)\setminus\{0\},$ $p>1$ and $u_0,f\in L^\infty(\mathbbm{H}^N),$ with $u_0\geq 0.$ Then, the following holds:
	\begin{enumerate}
		\item [(i)] There exists a fixed $T>0,$ and a unique mild solution $u\in C([0,T],L^\infty(\mathbbm{H}^N))$ to \eqref{eq without}. 
		\item [(ii)] The solution can be uniquely extended to a maximum interval $[0,T_{\text{max}}).$ Moreover, if $T_{\text{max}}$ is finite, then $\|u(t)\|_{L^\infty(\mathbbm{H}^N)}\longrightarrow\infty$ as $t\longrightarrow T_{\text{max}}.$
		\item [(iii)] Let $u_0,$ $f\in L^\infty(\mathbbm{H}^N)\cap L^q(\mathbbm{H}^N)$ for $q\in [1,\infty].$ Then
		\begin{align}
			u\in C([0,T_{\text{max}}),L^\infty(\mathbbm{H}^N))\cap C([0,T_{\text{max}}),L^q(\mathbbm{H}^N)).
		\end{align}
	\end{enumerate}

