\label{life}
	Let $\gamma\in [0,1),$ $\alpha\in (-1,0),$ and $p\in \bigg(1,\frac{Q+2\gamma-\mu(\lambda)-2\alpha}{Q-2-\mu(\lambda)-2\alpha}\bigg).$ Assume that $u_0\in L^\infty(\mathbbm{H}^N)$ with $u_0\geq 0,$ $0<\int_{\mathbbm{H}^N}\|\xi\|_H^{-\mu(\lambda)}f(\xi)d\xi<\infty$ and 
	\begin{align}\label{fxi}
		f(\xi)\geq \varepsilon\|\xi\|_{H}^{-2\beta}, \text{ for }\|\xi\|_{H}\geq 1, \beta\in \left(\frac{Q}{2}-\frac{\mu(\lambda)}{2},\frac{\gamma+p}{p-1}+\alpha\right) \text{ and }\varepsilon>0. 
	\end{align} 
	Then for any local-in-time solution $u_\varepsilon$ to \eqref{eq 0.1}, the following estimate on $T_\varepsilon$ is valid: 
	\begin{align}
		T_\varepsilon\leq C\varepsilon^{\big({\beta-\frac{\gamma+p}{p-1}-\alpha}\big)^{-1}}, 
	\end{align}
	for some constant $C>0$ independent of $T_\varepsilon.$

entries.proof:
In proving this result, we make use of the test functions introduced in the proof of Theorem \ref{Thm Blowup O}. Let $u_\varepsilon$ be local-in-time solution to \eqref{eq 0.1} with its maximal time $T_\varepsilon$ and also define $v_\varepsilon(\xi,t)\coloneqq\|\xi\|_{H}^{{\mu(\lambda)}}u_\varepsilon(\xi,t).$
	Now, for a fixed 
	\begin{align}
		l=1+\frac{p+\gamma}{p-1},
	\end{align}
	we define a function \begin{align}
		\phi(\xi,t)=\phi_1(\xi)\phi_2(t).
	\end{align} 
	Here
	\begin{align}
		\phi_1(\xi)=\varphi\left(\frac{\|\xi\|_{H}}{T_{\varepsilon}^{\frac{1}{2}}}\right), \, \phi_2(t)=\left(1-\frac{t}{T_\varepsilon}\right)^l,
	\end{align}
	and $\varphi$ is the same function appearing in \eqref{Phip}.
	Now, proceeding along similar lines as in the proof of Theorem \ref{Thm Blowup O}, and incorporating the following change of variables 
	\begin{align}\label{ch var}
		\xi'=\Phi_{T_\varepsilon^{-\frac{1}{2}}}\xi \text{ and } t'=T_\varepsilon^{-1}t,
	\end{align}
	provides
	\begin{align}\label{lepo}
		\\(1&-2\varepsilon)\int_0^{T_\varepsilon}\int_{B^{H}_{2\sqrt T_\varepsilon}}\|\xi\|_{H}^{{-(p+1)\mu(\lambda)}}|v_\varepsilon|^pI^\gamma_{T_\varepsilon^-}\phi d\xi dt+\int_{B^{H}_{2\sqrt T_\varepsilon}}\|\xi\|_{H}^{-2\mu(\lambda)}v_0\phi(0,\xi)d\xi+\int_0^{T_\varepsilon}\int_{B^{H}_{2\sqrt T_\varepsilon}} \|\xi\|_{H}^{-\mu(\lambda)}t^\alpha f\phi d\xi dt\\&\leq C(\varepsilon){T_\varepsilon}^{\frac{Q}{2}+1-\frac{\gamma+p}{p-1}-\frac{\mu(\lambda)}{2}}\int_{0}^1\int_{B^{H}_{2}}\|\xi'\|_{H}^{-{\mu(\lambda)}}\big(\phi_1\big(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\big)\big)^{\frac{-1}{p-1}}(I^\gamma_{T_\varepsilon T^-}\phi_2(T_\varepsilon t'))^{-\frac{1}{p-1}}\phi_1(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi')^{\frac{p}{p-1}}|\partial_t\phi_2(T_\varepsilon t')|^{\frac{p}{p-1}}d\xi'dt'\\
		&\quad+C_1C(\varepsilon)T_\varepsilon^{\frac{Q}{2}+1-\frac{\gamma+p}{p-1}-\frac{\mu(\lambda)}{2}}\times \\
		&\qquad \int_0^1\int_{B^{H}_{2}}\|\xi'\|_{H}^{\mu(\lambda)\left(\frac{p+1}{p-1}\right)}\big(\phi_1\big(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\big)\big)^{{-\frac{1}{p-1}}}(I^\gamma_{T_\varepsilon T^-}\phi_2(T_\varepsilon t'))^{-\frac{1}{p-1}}(\phi_2(T_\varepsilon t'))^{\frac{p}{p-1}}(L_H\phi_1(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'))^{\frac{p}{p-1}}d\xi'dt',
	\end{align}
	for some constant $C_1$ independent of $T_\varepsilon,$ since $\phi_1\in C_c^\infty(\mathbbm{H}^N).$ Using the facts that $u_0\geq 0$ and $\epsilon$ is arbitrarily small together with the following relation
	\begin{align}\label{s3}
		\int_0^{T_\varepsilon}\int_{\mathbbm{H}^N}\|\xi\|_{H}^{-\mu(\lambda)}t^\alpha f\phi d\xi dt&=T_\varepsilon^{(\alpha+1)}\int_{\mathbbm{H}^N}\|\xi\|_{H}^{-\mu(\lambda)}f(\xi)\phi_1(\xi)d\xi\int_0^1t'^\alpha \phi_2(T_\varepsilon t')dt'\\
		&\geq   CT_\varepsilon^{(\alpha+1)}\int_{\mathbbm{H}^N}\|\xi\|_{H}^{-\mu(\lambda)}f(\xi)\phi_1(\xi) d\xi,
	\end{align}
	in the expression \eqref{lepo} yields
	\begin{align}
		CT_\varepsilon^{(\alpha+1)}\int_{\mathbbm{H}^N}\|\xi\|_H^{-\mu(\lambda)}f(\xi)\phi_1(\xi)d\xi
		&\leq CT_\varepsilon^{\frac{Q}{2}+1-\frac{\gamma+p}{p-1}-\frac{\mu(\lambda)}{2}},
	\end{align}
	for some positive constant $C$ independent of $T_\varepsilon.$ This simplifies to
	\begin{align}\label{s10}
		\int_{\mathbbm{H}^N}\|\xi\|_{H}^{-\mu(\lambda)}f(\xi)\phi_1(\xi)d\xi
		\leq CT_\varepsilon^{\frac{Q}{2}-\frac{\gamma+p}{p-1}-\alpha-\frac{\mu(\lambda)}{2}}.
	\end{align}
	Further, using the estimate \eqref{fxi} together with \eqref{ch var}, we obtain
	\begin{align}\label{mt0}
		\int_{\mathbbm{H}^N}\|\xi\|_{H}^{-\mu(\lambda)}f(\xi)\phi_1(\xi)d\xi&=T_\varepsilon^{\frac{Q}{2}}\int_{\mathbbm{H}^N}\|\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi\|_{H}^{-\mu(\lambda)}f\bigg(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\bigg)\phi_1\bigg(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\bigg)d\xi'\\
		&\geq \varepsilon T_\varepsilon^{\frac{Q}{2}-\beta-\frac{\mu(\lambda)}{2}}\int_{\mathbbm{H}^N\setminus B^{H}_{\frac{1}{\sqrt{T}_\varepsilon}}}\|\xi'\|_{H}^{-\mu(\lambda)}\|\xi'\|_{H}^{-2\beta}\phi_1\bigg(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\bigg)d\xi'\\
		&\geq \varepsilon T_\varepsilon^{\frac{Q}{2}-\beta-\frac{\mu(\lambda)}{2} }\int_{\mathbbm{H}^N\setminus B^{H}_{\frac{1}{\sqrt{T}}}}\|\xi'\|_{H}^{-2\beta-\mu(\lambda)}\phi_1\bigg(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\bigg)d\xi',
	\end{align}
	for all $T\leq T_\varepsilon.$ Here, $\Phi$ denotes the dilation given by \eqref{dil}.
	Finally, utilizing \eqref{mt0} in \eqref{s10} yields
	\begin{align}
		\varepsilon T_\varepsilon^{\frac{Q}{2}-\beta-\frac{\mu(\lambda)}{2}}\int_{\mathbbm{H}^N\setminus B^{H}_{\frac{1}{\sqrt{T}}}}\|\xi'\|_{H}^{-2\beta-\mu(\lambda)}\phi_1\bigg(\Phi_{T_\varepsilon^{\frac{1}{2}}}\xi'\bigg)d\xi'\leq CT_\varepsilon^{\frac{Q}{2}-\frac{\gamma+p}{p-1}-\alpha-\frac{\mu(\lambda)}{2}}.
	\end{align}
Furthermore, in view of the fact that $2\beta>Q-\mu$ (see \eqref{fxi}), we get
	\begin{align}
		\varepsilon&\leq CT_\varepsilon^{\frac{Q}{2}-\frac{\gamma+p}{p-1}-\alpha-\frac{Q}{2}+\beta}\\
		&=CT_\varepsilon^{-\frac{\gamma+p}{p-1}-\alpha+\beta}.
	\end{align}
	This deduces
	\begin{align}
		T_\varepsilon\leq C\varepsilon^{\big({\beta-\frac{\gamma+p}{p-1}-\alpha}\big)^{-1}},
	\end{align}
	for some positive constant $C$ independent of $T_\varepsilon.$ This completes the proof.

